-- =====================================================================
-- PriceMint — Supabase Production Schema
-- Run this ONCE in your Supabase project's SQL Editor:
-- Dashboard -> SQL Editor -> New query -> paste this whole file -> Run
-- =====================================================================

-- ---------------------------------------------------------------------
-- 1. PRODUCTS  (single source of truth for the entire catalog)
-- ---------------------------------------------------------------------
create table if not exists public.products (
  id                 text primary key,
  title              text not null,
  brand              text,
  category           text not null,
  rating             numeric(2,1) default 4.0,
  review_count       integer default 0,
  lowest_price       numeric not null,
  original_price     numeric not null,
  discount           integer default 0,
  in_stock           boolean default true,
  thumbnail          text,
  specs              jsonb default '{}'::jsonb,
  prices             jsonb default '[]'::jsonb,   -- [{platform, price, color, url, deliveryEstimate, cashback, coupon}]
  history            jsonb default '[]'::jsonb,   -- [{date, price}]
  ai_summary         jsonb,                        -- {features, pros, cons, recommendation}
  cheapest_platform  text,
  cheapest_url       text,
  is_trending        boolean default false,
  is_price_drop      boolean default false,
  is_editor_pick     boolean default false,
  is_ai_recommended  boolean default false,
  is_most_compared   boolean default false,
  is_active          boolean default true,
  created_at         timestamptz not null default now()
);

create index if not exists idx_products_category on public.products (category);
create index if not exists idx_products_active on public.products (is_active);
create index if not exists idx_products_discount on public.products (discount desc);

alter table public.products enable row level security;

drop policy if exists "Public can read active products" on public.products;
create policy "Public can read active products"
  on public.products for select
  using (is_active = true);

-- ---------------------------------------------------------------------
-- 2. ADMINS  (user IDs allowed to manage the catalog via admin.html)
-- ---------------------------------------------------------------------
create table if not exists public.admins (
  user_id    uuid primary key references auth.users(id) on delete cascade,
  created_at timestamptz not null default now()
);

alter table public.admins enable row level security;

drop policy if exists "Users can check their own admin status" on public.admins;
create policy "Users can check their own admin status"
  on public.admins for select
  using (auth.uid() = user_id);

-- Admin write access to products (insert/update/delete) — only for users
-- present in the admins table above.
drop policy if exists "Admins can insert products" on public.products;
create policy "Admins can insert products"
  on public.products for insert
  with check (exists (select 1 from public.admins where user_id = auth.uid()));

drop policy if exists "Admins can update products" on public.products;
create policy "Admins can update products"
  on public.products for update
  using (exists (select 1 from public.admins where user_id = auth.uid()));

drop policy if exists "Admins can delete products" on public.products;
create policy "Admins can delete products"
  on public.products for delete
  using (exists (select 1 from public.admins where user_id = auth.uid()));

-- IMPORTANT: after creating your account by signing up on the site,
-- run this once (replace with your real user id from Authentication ->
-- Users in the Supabase dashboard) to make yourself an admin:
--   insert into public.admins (user_id) values ('YOUR-USER-UUID-HERE');

-- ---------------------------------------------------------------------
-- 3. PRICE ALERTS  (formerly the Express /api/wishlist endpoints)
-- ---------------------------------------------------------------------
create table if not exists public.price_alerts (
  id            uuid primary key default gen_random_uuid(),
  user_id       uuid not null references auth.users(id) on delete cascade,
  product_id    text not null references public.products(id) on delete cascade,
  target_price  numeric not null,
  created_at    timestamptz not null default now(),
  unique (user_id, product_id)
);

alter table public.price_alerts enable row level security;

drop policy if exists "Users manage their own price alerts" on public.price_alerts;
create policy "Users manage their own price alerts"
  on public.price_alerts for all
  using (auth.uid() = user_id)
  with check (auth.uid() = user_id);

-- ---------------------------------------------------------------------
-- 4. SEED DATA — 30 demo products across 13 categories
--    (Prices/specs are illustrative placeholders — replace with live
--    scraped data once you wire up a real price-fetching pipeline.)
-- ---------------------------------------------------------------------
